import CoreSpotlight
import MobileCoreServices
import SwiftUI
import SwiftData // MARK: - ─── Spotlight 系统搜索集成 ─── /// 将联系人、案件和事件写入 Core Spotlight 索引， /// 让用户在系统 Spotlight 中就能搜到岛连中的内容， /// 点击结果后跳转到 App 内对应详情页。 /// Spotlight 索引管理器（单例，主线程安全） @MainActor final class SpotlightIndexManager { static let shared = SpotlightIndexManager() private init() {} // MARK: - 索引联系人 /// 将一位联系人写入 Spotlight 索引 /// 搜索关键词：姓名、单位、电话、邮箱 func indexPerson(_ person: Person) { let attributeSet = CSSearchableItemAttributeSet(contentType: .contact) attributeSet.displayName = person.name attributeSet.nickname = person.name if let firstOrg = person.orgUnits.first { attributeSet.organizationName = firstOrg.name attributeSet.organizationDepartment = firstOrg.department } attributeSet.jobTitle = person.title // 电话号码（格式化为可搜索） var phoneNumbers: [String] = [] if let phone = person.phone { phoneNumbers.append(phone) } if let phone2 = person.phone2 { phoneNumbers.append(phone2) } if !phoneNumbers.isEmpty { attributeSet.phoneNumbers = phoneNumbers } // 邮箱 if let email = person.email { attributeSet.emailAddresses = [email] } // 关键词 = 姓名 + 单位 + 角色名 var keywords: [String] = [person.name] if let firstOrg = person.orgUnits.first { keywords.append(firstOrg.name) } keywords.append(contentsOf: person.roleTypes.map(\.rawValue)) attributeSet.keywords = keywords // 描述 var desc = "律师联系人 · \(person.roleTypes.map(\.rawValue).joined(separator: "、"))" if let firstOrg = person.orgUnits.first { desc = "\(person.roleTypes.map(\.rawValue).joined(separator: "、")) · \(firstOrg.name)" } attributeSet.contentDescription = desc // 缩略图（可选：头像或角色图标色块） attributeSet.thumbnailData = roleColorThumbnail(for: person.roleTypes.first ?? .other) let identifier = "person.\(person.id)" let item = CSSearchableItem( uniqueIdentifier: identifier, domainIdentifier: "com.youmind.islandlink.person", attributeSet: attributeSet ) item.expirationDate = nil // 永不过期 CSSearchableIndex.default().indexSearchableItems([item]) { error in if let error { print("[SpotlightIndexManager] 索引联系人失败: \(error.localizedDescription)") } } } // MARK: - 索引案件 /// 将一个案件写入 Spotlight 索引 /// 搜索关键词：案件名称、案号、灵活字段值 func indexCase(_ caseItem: Case) { let attributeSet = CSSearchableItemAttributeSet(contentType: .content) attributeSet.displayName = caseItem.name attributeSet.title = caseItem.name // 副标题：案号 if let caseNumber = caseItem.caseNumber { attributeSet.contentDescription = caseNumber } // 关键词：名称 + 案号 + 灵活字段值 var keywords: [String] = [caseItem.name] if let caseNumber = caseItem.caseNumber { keywords.append(caseNumber) } keywords.append(contentsOf: caseItem.customFields.map { $0.value }) attributeSet.keywords = keywords // 缩略图（统一色调） attributeSet.thumbnailData = genericCaseThumbnail() let identifier = "case.\(caseItem.id)" let item = CSSearchableItem( uniqueIdentifier: identifier, domainIdentifier: "com.youmind.islandlink.case", attributeSet: attributeSet ) item.expirationDate = nil CSSearchableIndex.default().indexSearchableItems([item]) { error in if let error { print("[SpotlightIndexManager] 索引案件失败: \(error.localizedDescription)") } } } // MARK: - 索引事件 /// 将事件写入 Spotlight 索引 func indexEvent(_ event: Event) { let attributeSet = CSSearchableItemAttributeSet(contentType: .event) attributeSet.displayName = event.title attributeSet.title = event.title // 描述：类型 + 时间 + 地点 var descParts: [String] = [event.eventType.rawValue] if let date = event.date { descParts.append(date.formatted(.dateTime.month(.abbreviated).day().hour().minute())) } if let location = event.location, !location.isEmpty { descParts.append(location) } attributeSet.contentDescription = descParts.joined(separator: " · ") // 关键词 var keywords: [String] = [event.title, event.eventType.rawValue] if let location = event.location { keywords.append(location) } if let summary = event.summary { keywords.append(summary) } attributeSet.keywords = keywords // 开始日期（系统日历用） attributeSet.startDate = event.date let identifier = "event.\(event.id)" let item = CSSearchableItem( uniqueIdentifier: identifier, domainIdentifier: "com.youmind.islandlink.event", attributeSet: attributeSet ) item.expirationDate = event.date?.addingTimeInterval(7 * 24 * 3600) // 事件结束一周后过期 CSSearchableIndex.default().indexSearchableItems([item]) { error in if let error { print("[SpotlightIndexManager] 索引事件失败: \(error.localizedDescription)") } } } // MARK: - 移除索引 /// 从 Spotlight 中移除某联系人 func removePerson(_ person: Person) { let identifier = "person.\(person.id)" CSSearchableIndex.default().deleteSearchableItems(withIdentifiers: [identifier]) { error in if let error { print("[SpotlightIndexManager] 移除联系人索引失败: \(error.localizedDescription)") } } } /// 从 Spotlight 中移除某案件 func removeCase(_ caseItem: Case) { let identifier = "case.\(caseItem.id)" CSSearchableIndex.default().deleteSearchableItems(withIdentifiers: [identifier]) { error in if let error { print("[SpotlightIndexManager] 移除案件索引失败: \(error.localizedDescription)") } } } /// 从 Spotlight 中移除某事件 func removeEvent(_ event: Event) { let identifier = "event.\(event.id)" CSSearchableIndex.default().deleteSearchableItems(withIdentifiers: [identifier]) { error in if let error { print("[SpotlightIndexManager] 移除事件索引失败: \(error.localizedDescription)") } } } // MARK: - 全量重建索引 /// 全量重建所有联系人和案件的 Spotlight 索引 /// 建议在 App 启动或数据恢复时调用 func rebuildAllIndices(modelContext: ModelContext) { // 先清空当前域下所有索引 let domains: [String] = [ "com.youmind.islandlink.person", "com.youmind.islandlink.case", "com.youmind.islandlink.event" ] CSSearchableIndex.default().deleteSearchableItems(withDomainIdentifiers: domains) { error in if let error { print("[SpotlightIndexManager] 清空索引失败: \(error.localizedDescription)") } } // 重新索引联系人 let personDescriptor = FetchDescriptor<person>(sortBy: [SortDescriptor(\.name)]) if let persons = try? modelContext.fetch(personDescriptor) { for person in persons { indexPerson(person) } } // 重新索引案件 let caseDescriptor = FetchDescriptor<case>(sortBy: [SortDescriptor(\.name)]) if let cases = try? modelContext.fetch(caseDescriptor) { for caseItem in cases { indexCase(caseItem) } } // 重新索引活跃事件 let eventDescriptor = FetchDescriptor<event>( predicate: #Predicate { event in (event.statusRaw == "planned" || event.statusRaw == "confirmed") }, sortBy: [SortDescriptor(\.date)] ) if let events = try? modelContext.fetch(eventDescriptor) { for event in events { indexEvent(event) } } print("[SpotlightIndexManager] 全量 Spotlight 索引重建完成。") } // MARK: - 缩略图生成（纯色块 · iOS/macOS 兼容） /// 生成角色色系缩略图 private func roleColorThumbnail(for role: PersonRoleType) -> Data? { #if os(macOS) return nil // macOS 上 Spotlight 缩略图简化处理 #else let size = CGSize(width: 80, height: 80) let renderer = UIGraphicsImageRenderer(size: size) let image = renderer.image { ctx in let color: UIColor switch role { case .judge: color = UIColor(red: 0.753, green: 0.224, blue: 0.169, alpha: 1) case .prosecutor: color = UIColor(red: 0.173, green: 0.435, blue: 0.675, alpha: 1) case .lawyer: color = UIColor(red: 0.239, green: 0.478, blue: 0.294, alpha: 1) case .party: color = UIColor(red: 0.831, green: 0.455, blue: 0.290, alpha: 1) case .police: color = UIColor(red: 0.357, green: 0.314, blue: 0.588, alpha: 1) case .witness: color = UIColor(red: 0.176, green: 0.498, blue: 0.459, alpha: 1) case .clerk: color = UIColor(red: 0.420, green: 0.314, blue: 0.275, alpha: 1) case .expert: color = UIColor(red: 0.659, green: 0.271, blue: 0.431, alpha: 1) case .other: color = UIColor(red: 0.380, green: 0.380, blue: 0.380, alpha: 1) } ctx.cgContext.setFillColor(color.cgColor) ctx.cgContext.fillEllipse(in: CGRect(origin: .zero, size: size)) } return image.pngData() #endif } /// 生成统一的案件缩略图（深蓝底色） private func genericCaseThumbnail() -> Data? { #if os(macOS) return nil #else let size = CGSize(width: 80, height: 80) let renderer = UIGraphicsImageRenderer(size: size) let image = renderer.image { ctx in let color = UIColor(red: 0.086, green: 0.396, blue: 0.753, alpha: 1) ctx.cgContext.setFillColor(color.cgColor) ctx.cgContext.fillRoundedRect( CGRect(origin: .zero, size: size), cornerSize: CGSize(width: 16, height: 16) ) } return image.pngData() #endif } } // MARK: - ─── CSIndexExtensionRequestHandler ─── /// Spotlight 扩展处理：当用户在系统 Spotlight 中点击岛连的搜索结果时， /// 跳转到 App 内对应详情页。具体跳转逻辑在 App 端 SceneDelegate / AppDelegate /// 中通过 `continueUserActivity` 处理 `CSSearchableItemActionType`。 import CoreSpotlight final class IslandLinkSpotlightHandler: CSIndexExtensionRequestHandler { override func searchableIndex( _ searchableIndex: CSSearchableIndex, reindexAllSearchableItemsWithAcknowledgementHandler acknowledgementHandler: @escaping () -> Void ) { // 当系统请求重建索引时，通知主 App 进行全量重建 // 可通过 Darwin Notification 或共享存储标记来触发 print("[IslandLinkSpotlightHandler] 系统请求重建 Spotlight 索引") acknowledgementHandler() } override func searchableIndex( _ searchableIndex: CSSearchableIndex, reindexSearchableItemsWithIdentifiers identifiers: [String], acknowledgementHandler: @escaping () -> Void ) { // 部分索引项需要重建时 print("[IslandLinkSpotlightHandler] 系统请求重建部分索引：\(identifiers)") acknowledgementHandler() } }
